const targets = $input.all().map(i => i.json);

// Mobile User-Agents only — widget renders only on mobile
const mobileUAs = [
  'Mozilla/5.0 (iPhone; CPU iPhone OS 17_3 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/17.3 Mobile/15E148 Safari/604.1',
  'Mozilla/5.0 (Linux; Android 14; SM-S918B) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.6261.64 Mobile Safari/537.36',
  'Mozilla/5.0 (Linux; Android 13; Pixel 7) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.6261.64 Mobile Safari/537.36',
  'Mozilla/5.0 (iPhone; CPU iPhone OS 16_6 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/16.6 Mobile/15E148 Safari/604.1'
];

const referers = [
  'https://www.google.com/',
  'https://yandex.ru/',
  'https://www.bing.com/',
  'https://dzen.ru/',
  ''
];

return targets.map(t => ({
  json: {
    target_id: t.id,
    site_url: t.site_url,
    country_code: t.country_code,
    proxy_url: t.proxy_url || '',
    proxy_type: t.proxy_type || 'socks5',
    user_agent: mobileUAs[Math.floor(Math.random() * mobileUAs.length)],
    referer: referers[Math.floor(Math.random() * referers.length)]
  }
}));

const input = $input.first().json;
const html = input.data || input.body || (typeof input === 'string' ? input : '');
const scanReq = $('Prepare Scan Requests').first().json;
const siteUrl = scanReq.site_url;
const geo = scanReq.country_code;
const proxyUrl = scanReq.proxy_url;
const userAgent = scanReq.user_agent;

if (input.error || input.code >= 400) {
  return [{ json: {
    site_url: siteUrl,
    country_code: geo,
    widget_found: false,
    block_ids: [],
    error: input.error || `HTTP ${input.code || 'unknown'}`,
    scanned_at: $now.toISO()
  }}];
}

// Find data-gz-block UUIDs
// Matches both normal HTML: data-gz-block="UUID"
// and escaped JSON in scripts: data-gz-block=\\\"UUID\\\"
const blockIds = [];
const seen = new Set();

// Pattern 1: normal HTML attributes
const blockRegex1 = /data-gz-block=["']([0-9a-f-]{36})["']/gi;
let m;
while ((m = blockRegex1.exec(html)) !== null) {
  if (!seen.has(m[1])) { seen.add(m[1]); blockIds.push(m[1]); }
}

// Pattern 2: escaped quotes inside JSON/JS strings (e.g. \"UUID\")
const blockRegex2 = /data-gz-block=\\+["']([0-9a-f-]{36})\\+["']/gi;
while ((m = blockRegex2.exec(html)) !== null) {
  if (!seen.has(m[1])) { seen.add(m[1]); blockIds.push(m[1]); }
}

// Generate surfer_uuid for render API
const surferUuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
  const r = Math.random() * 16 | 0;
  return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
});

if (blockIds.length === 0) {
  return [{ json: {
    site_url: siteUrl,
    country_code: geo,
    widget_found: false,
    block_ids: [],
    render_url: '',
    proxy_url: proxyUrl,
    user_agent: userAgent,
    scanned_at: $now.toISO()
  }}];
}

// Build render API URL for first block
const blockUuid = blockIds[0];
const pageLoadUuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
  const r = Math.random() * 16 | 0;
  return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
});
const renderUrl = `https://render.sustainablyaware.com/v5/render?surfer_uuid=${surferUuid}&referrer=${encodeURIComponent(siteUrl)}&pre_referrer=${encodeURIComponent(siteUrl)}&time_zone=3&page_load_uuid=${pageLoadUuid}&page_depth=1&m1olt2jjczm=${blockUuid}&block_uuid=${blockUuid}&refresh_depth=1`;

return [{ json: {
  site_url: siteUrl,
  country_code: geo,
  widget_found: true,
  block_ids: blockIds,
  render_url: renderUrl,
  proxy_url: proxyUrl,
  user_agent: userAgent,
  scanned_at: $now.toISO()
}}];

const input = $input.first().json;
const renderHtml = input.data || input.body || (typeof input === 'string' ? input : '');
const blockData = $('Extract Block IDs').first().json;
const siteUrl = blockData.site_url;
const geo = blockData.country_code;

if (!renderHtml || renderHtml.length < 50) {
  return [{ json: {
    site_url: siteUrl,
    country_code: geo,
    widget_found: true,
    block_ids: blockData.block_ids,
    teasers_found: 0,
    teasers: [],
    error: 'Render API returned empty or short response',
    scanned_at: blockData.scanned_at
  }}];
}

const teasers = [];

// Parse teaser titles from rendered HTML
// Pattern: <div class="block-*-media__title">TITLE</div>
const titleRegex = /class=["'][^"']*media__title["'][^>]*>\s*([\s\S]*?)\s*<\/div>/gi;
let titleMatch;
let position = 0;
while ((titleMatch = titleRegex.exec(renderHtml)) !== null) {
  position++;
  const title = titleMatch[1].replace(/<[^>]+>/g, '').trim();
  if (title.length > 5) {
    teasers.push({ position, title });
  }
}

// Extract image URLs from background-image:url('...')
const imageUrls = [];
const imgRegex = /class=["'][^"']*media__img["'][^>]*style=["'][^"']*background-image:\s*url\(['\"]?([^'\")]+)['\"]?\)/gi;
let imgMatch;
while ((imgMatch = imgRegex.exec(renderHtml)) !== null) {
  // Decode HTML entities and strip surrounding quotes
  const url = imgMatch[1]
    .replace(/&amp;/g, '&')
    .replace(/&#39;/g, '')
    .replace(/&quot;/g, '')
    .replace(/^['"]|['"]$/g, '');
  if (url.startsWith('http')) imageUrls.push(url);
}

// Also extract click URLs to match with our ads
const clickUrls = [];
const clickRegex = /href=["'](https:\/\/render\.sustainablyaware\.com\/v1\/direct\/click[^"']*)["']/gi;
let clickMatch;
while ((clickMatch = clickRegex.exec(renderHtml)) !== null) {
  clickUrls.push(clickMatch[1].replace(/&amp;/g, '&'));
}

// Merge all extracted data per teaser
for (let i = 0; i < teasers.length; i++) {
  // Click URL and media_id
  if (i < clickUrls.length) {
    const mediaMatch = clickUrls[i].match(/media=(\d+)/);
    if (mediaMatch) {
      teasers[i].media_id = mediaMatch[1];
    }
    teasers[i].click_url = clickUrls[i];
  }
  // Image URL
  if (i < imageUrls.length) {
    teasers[i].image_url = imageUrls[i];
  }
}

return [{ json: {
  site_url: siteUrl,
  country_code: geo,
  widget_found: true,
  block_ids: blockData.block_ids,
  teasers_found: teasers.length,
  teasers: teasers,
  scanned_at: blockData.scanned_at
}}];

// Filter out teasers already in DB with known landing URL
// RATE LIMIT: max 4 NEW teasers per scan to avoid anti-fraud
const knownRows = $input.all().map(i => i.json);

// Build map: title -> destination_url (from DB)
const knownMap = new Map();
knownRows.forEach(r => {
  if (r.title) knownMap.set(r.title, r.destination_url || '');
});

const data = $('Parse Teasers from Render').first().json;
const teasers = data.teasers || [];
const siteUrl = data.site_url;
const geo = data.country_code;
const proxyUrl = $('Prepare Scan Requests').first().json.proxy_url || '';

if (teasers.length === 0) {
  return [{ json: { skip: true, site_url: siteUrl, country_code: geo } }];
}

// Helper: parse tracking params from a landing URL
function parseTrackingParams(url) {
  if (!url || !url.startsWith('http')) return {};
  try {
    const u = new URL(url);
    const p = u.searchParams;
    return {
      landing_domain: u.hostname,
      geozo_block_id: parseInt(p.get('blockid') || p.get('block') || p.get('source')) || null,
      geozo_site_id: parseInt(p.get('Siteid')) || null,
      geozo_ad_id: parseInt(p.get('Adid') || p.get('creative_id')) || null,
      geozo_adgroup_id: parseInt(p.get('adgroupid') || p.get('ad_campaign_id')) || null,
      cost: p.get('cost') || null
    };
  } catch(e) { return {}; }
}

const MAX_RESOLVES_PER_SCAN = 4;

// Only resolve teasers we haven't resolved before
const newTeasers = teasers.filter(t => t.click_url && !knownMap.has(t.title));
// Also keep already-known ones to update position/image (but skip resolve)
const knownTeasers = teasers.filter(t => knownMap.has(t.title));

const results = [];

// New teasers get full resolve treatment
const toResolve = newTeasers.slice(0, MAX_RESOLVES_PER_SCAN);
toResolve.forEach((t, idx) => {
  results.push({
    json: {
      title: t.title,
      position: t.position,
      media_id: t.media_id || null,
      click_url: t.click_url,
      image_url: t.image_url || null,
      site_url: siteUrl,
      country_code: geo,
      proxy_url: proxyUrl,
      resolve_delay_ms: idx * 3000,
      needs_resolve: true
    }
  });
});

// Known teasers: parse tracking params from existing destination_url in DB
knownTeasers.forEach(t => {
  const existingUrl = knownMap.get(t.title);
  const params = parseTrackingParams(existingUrl);
  results.push({
    json: {
      title: t.title,
      position: t.position,
      media_id: t.media_id || null,
      click_url: t.click_url || null,
      image_url: t.image_url || null,
      site_url: siteUrl,
      country_code: geo,
      proxy_url: proxyUrl,
      needs_resolve: false,
      landing_url: existingUrl || null,
      landing_domain: params.landing_domain || null,
      geozo_block_id: params.geozo_block_id || null,
      geozo_site_id: params.geozo_site_id || null,
      geozo_ad_id: params.geozo_ad_id || null,
      geozo_adgroup_id: params.geozo_adgroup_id || null,
      cost: params.cost || null
    }
  });
});

if (results.length === 0) {
  return [{ json: { skip: true, site_url: siteUrl, country_code: geo } }];
}

return results;

// Wait before resolving to respect rate limits (3s between clicks)
const item = $input.first().json;
const delay = item.resolve_delay_ms || 0;
if (delay > 0) {
  await new Promise(r => setTimeout(r, delay));
}
return [$input.first()];

const httpResponse = $input.first().json;
const teaser = $('Rate Limit Wait').first().json;

// Extract landing URL from HTTP response
// Tracker returns HTTP 200 with meta refresh / JS redirect to the actual landing
let landingUrl = '';

// 1. Check if HTTP Request followed HTTP redirects to a non-tracker domain
if (httpResponse.url && !httpResponse.url.includes('sustainablyaware.com')) {
  landingUrl = httpResponse.url;
} else if (httpResponse.responseUrl && !httpResponse.responseUrl.includes('sustainablyaware.com')) {
  landingUrl = httpResponse.responseUrl;
}

// 2. Parse HTML body for meta refresh / JS redirect (tracker uses HTTP 200 + meta refresh)
if (!landingUrl) {
  const body = httpResponse.body || httpResponse.data || '';
  if (typeof body === 'string') {
    // meta refresh: <meta http-equiv="refresh" content="0; URL=https://silentsloth.com/...">
    const metaMatch = body.match(/http-equiv=["']refresh["'][^>]*content=["'][^"']*url=([^"'\s>]+)/i);
    if (metaMatch) landingUrl = metaMatch[1];
    // JS redirect: window.location = "https://silentsloth.com/..."
    if (!landingUrl) {
      const jsMatch = body.match(/(?:window\.location|location\.href|location\.replace)\s*[=\(]\s*["']([^"']+)["']/i);
      if (jsMatch) landingUrl = jsMatch[1];
    }
  }
}

if (!landingUrl) {
  landingUrl = 'resolve_failed';
}

// Extract tracking params from landing URL
// Different trackers use different param names:
//   silentsloth: blockid, Siteid, Adid, adgroupid
//   breezefieldbox: block, source, creative_id, ad_campaign_id, affiliate_id, cost
let trackingParams = {};
try {
  if (landingUrl && landingUrl.startsWith('http')) {
    const u = new URL(landingUrl);
    const p = u.searchParams;
    trackingParams = {
      landing_domain: u.hostname,
      landing_path: u.pathname,
      geozo_block_id: parseInt(p.get('blockid') || p.get('block') || p.get('source')) || null,
      geozo_site_id: parseInt(p.get('Siteid')) || null,
      geozo_ad_id: parseInt(p.get('Adid') || p.get('creative_id')) || null,
      geozo_adgroup_id: parseInt(p.get('adgroupid') || p.get('ad_campaign_id')) || null,
      cost: p.get('cost') || null,
      stream_uuid: p.get('stream_uuid') || p.get('external_id') || null
    };
  }
} catch(e) { /* ignore URL parse errors */ }

return [{ json: {
  title: teaser.title,
  position: teaser.position,
  media_id: teaser.media_id,
  click_url: teaser.click_url,
  image_url: teaser.image_url,
  landing_url: landingUrl,
  ...trackingParams,
  site_url: teaser.site_url,
  country_code: teaser.country_code
}}];
